import{c as a,Q as i,j as c,m as o}from"./chunks/framework.iD28w_5a.js";const u=JSON.parse('{"title":"PCI 总线 & AHCI SATA 驱动","description":"","frontmatter":{},"headers":[],"relativePath":"document/kernel/drivers/ahci_pci.md","filePath":"document/kernel/drivers/ahci_pci.md","lastUpdated":1777209094000}'),r={name:"document/kernel/drivers/ahci_pci.md"};function d(l,e,p,t,h,n){return i(),c("div",null,[...e[0]||(e[0]=[o('<h1 id="pci-总线-ahci-sata-驱动" tabindex="-1">PCI 总线 &amp; AHCI SATA 驱动 <a class="header-anchor" href="#pci-总线-ahci-sata-驱动" aria-label="Permalink to &quot;PCI 总线 &amp; AHCI SATA 驱动&quot;">​</a></h1><blockquote><p>里程碑: <code>025_driver_ahci</code></p></blockquote><h2 id="功能概述" tabindex="-1">功能概述 <a class="header-anchor" href="#功能概述" aria-label="Permalink to &quot;功能概述&quot;">​</a></h2><p>PCI 配置空间枚举 + AHCI SATA 控制器驱动。通过 BAR5 MMIO 操作 HBA 端口，支持 DMA 读写。</p><h2 id="pci-总线-kernel-drivers-pci-pci-hpp-cpp" tabindex="-1">PCI 总线 (<code>kernel/drivers/pci/pci.hpp/cpp</code>) <a class="header-anchor" href="#pci-总线-kernel-drivers-pci-pci-hpp-cpp" aria-label="Permalink to &quot;PCI 总线 (`kernel/drivers/pci/pci.hpp/cpp`)&quot;">​</a></h2><h3 id="数据结构" tabindex="-1">数据结构 <a class="header-anchor" href="#数据结构" aria-label="Permalink to &quot;数据结构&quot;">​</a></h3><ul><li><code>PCIDevice {bus, slot, func, vendor_id, device_id, class_code, subclass, prog_if, bar[6]}</code></li></ul><h3 id="api" tabindex="-1">API <a class="header-anchor" href="#api" aria-label="Permalink to &quot;API&quot;">​</a></h3><ul><li><code>pci_read(bus, slot, func, reg)</code> — 写 <code>0xCF8</code>，读 <code>0xCFC</code></li><li><code>pci_write(bus, slot, func, reg, val)</code> — 写 <code>0xCF8</code> + <code>0xCFC</code></li><li><code>pci_find_ahci(PCIDevice&amp; out)</code> — 枚举 class=0x01 subclass=0x06</li></ul><h2 id="ahci-控制器-kernel-drivers-ahci-ahci-hpp-cpp" tabindex="-1">AHCI 控制器 (<code>kernel/drivers/ahci/ahci.hpp/cpp</code>) <a class="header-anchor" href="#ahci-控制器-kernel-drivers-ahci-ahci-hpp-cpp" aria-label="Permalink to &quot;AHCI 控制器 (`kernel/drivers/ahci/ahci.hpp/cpp`)&quot;">​</a></h2><h3 id="数据结构-1" tabindex="-1">数据结构 <a class="header-anchor" href="#数据结构-1" aria-label="Permalink to &quot;数据结构&quot;">​</a></h3><ul><li><code>HBAmem [[gnu::packed]]</code> — cap/ghc/is/pi 等 HBA 寄存器</li><li><code>HBAport [[gnu::packed]]</code> — clb/fb/is/ie/cmd 等端口寄存器</li></ul><h3 id="初始化-ahci-init" tabindex="-1">初始化 (<code>ahci_init()</code>) <a class="header-anchor" href="#初始化-ahci-init" aria-label="Permalink to &quot;初始化 (`ahci_init()`)&quot;">​</a></h3><ol><li>映射 BAR5 MMIO (<code>VMM::map</code>)</li><li>检测 <code>pi</code> 位图确定活跃端口</li><li>为每端口分配 Command List (32x32B) + FIS Buffer (256B)，物理连续且对齐</li></ol><h3 id="读写-api" tabindex="-1">读写 API <a class="header-anchor" href="#读写-api" aria-label="Permalink to &quot;读写 API&quot;">​</a></h3><ul><li><code>ahci_read(port, lba, count, buf)</code> — 构造 CFIS (ATA READ DMA EXT=0x25) + PRDT，写 <code>port.ci</code>，轮询 <code>port.is</code></li><li><code>ahci_write(port, lba, count, buf)</code> — 同上，命令为 WRITE DMA EXT=0x35</li></ul><h3 id="单例模式" tabindex="-1">单例模式 <a class="header-anchor" href="#单例模式" aria-label="Permalink to &quot;单例模式&quot;">​</a></h3><ul><li><code>AHCI::instance()</code> / <code>AHCI::set_instance()</code> — 替代裸全局变量</li></ul><h2 id="源码位置" tabindex="-1">源码位置 <a class="header-anchor" href="#源码位置" aria-label="Permalink to &quot;源码位置&quot;">​</a></h2><ul><li><code>kernel/drivers/pci/pci.hpp/cpp</code> — PCI 枚举</li><li><code>kernel/drivers/pci/pci_config.hpp</code> — PCI 常量</li><li><code>kernel/drivers/ahci/ahci.hpp/cpp</code> — AHCI 驱动</li><li><code>kernel/drivers/ahci/ahci_config.hpp</code> — AHCI 配置</li></ul>',20)])])}const _=a(r,[["render",d]]);export{u as __pageData,_ as default};
